import React, { useCallback, useMemo } from 'react';
import { SearchInput, type SearchInputConfig } from '@linm-soft/common-components';
import { masterService } from '../../../services/master/masterService';
import type { CustomerGroupDto } from '../../../services/master/models';
import { MAX_CUSTOMER_GROUP_LEVEL } from '../../../utils/customerGroupTree';

export const CUSTOMER_GROUPS_CATALOG_KIND = 'customer-groups';

/** Chỉ cấp 1–3 có thể làm nhóm cha (cấp 4 là lá). */
const MAX_PARENT_LEVEL = MAX_CUSTOMER_GROUP_LEVEL - 1;

type Props = {
  parentId?: string;
  parentCode?: string;
  parentName?: string;
  disabled?: boolean;
  error?: string;
  onChange: (parent: CustomerGroupDto) => void;
  onClear: () => void;
  testId?: string;
};

function buildParentSearchConfig(
  search: (params: {
    search?: string;
    page?: number;
    pageSize?: number;
  }) => ReturnType<typeof masterService.getCustomerGroups>,
): SearchInputConfig<CustomerGroupDto> {
  return {
    api: {
      getItemKey: item => item.customerGroupId,
      search: async ({ search: term, page, pageSize }) => {
        const data = await search({ search: term, page, pageSize });
        const size = data.pageSize || 20;
        const totalPages = Math.max(1, Math.ceil(data.totalCount / size));
        return { items: data.items, page: data.page, totalPages };
      },
    },
    display: {
      getPrimaryDisplay: item => item.code,
      getSecondaryDisplay: item => item.name,
      getSingleDisplay: item => `${item.code} — ${item.name}`,
    },
    columns: [
      { key: 'code', variant: 'badge', width: '7rem', render: item => item.code || '—' },
      { key: 'name', variant: 'primary', render: item => item.name || '—' },
      { key: 'level', variant: 'meta', width: '4rem', render: item => String(item.level ?? '—') },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã nhóm' },
        { key: 'name', label: 'Tên nhóm' },
        { key: 'level', label: 'Cấp' },
      ],
    },
    dropdownMatch: 'row',
    dropdownMinWidth: '24rem',
    dropdownPortal: true,
    texts: { empty: 'Không có nhóm cha phù hợp' },
  };
}

/** Lookup nhóm cha — cấp 1–3; L2–L4 chỉ quản trị cây danh mục. */
export const CustomerGroupParentLookupField: React.FC<Props> = ({
  parentId,
  parentCode,
  parentName,
  disabled,
  error,
  onChange,
  onClear,
  testId,
}) => {
  const search = useCallback(
    (params: { search?: string; page?: number; pageSize?: number }) =>
      masterService.getCustomerGroups({
        search: params.search,
        page: params.page,
        pageSize: params.pageSize,
        isActive: true,
        maxLevel: MAX_PARENT_LEVEL,
      }),
    [],
  );

  const effectiveConfig = useMemo(() => buildParentSearchConfig(search), [search]);

  const primaryDisplay = useMemo(() => {
    if (!parentId) return '';
    if (parentCode && parentName) return `${parentCode} — ${parentName}`;
    return parentName ?? parentCode ?? '';
  }, [parentId, parentCode, parentName]);

  return (
    <SearchInput
      config={effectiveConfig}
      value={parentId ?? ''}
      primaryDisplay={primaryDisplay}
      onChange={onChange}
      onClear={onClear}
      disabled={disabled}
      error={error}
      showLabel={false}
      showSecondaryInput={false}
      placeholder="Chọn nhóm cha (tùy chọn)..."
      data-testid={testId}
    />
  );
};
